import{Functions,Server}from"Beckhoff.TwinCAT.HMI.Framework/index.esm.js";export function EventClassesProvider(rowValue,dataIndex,rowNumber){let classes=[];switch(rowValue.type){case Server.Events.Type.Message:classes.push("message");break;case Server.Events.Type.Alarm:classes.push("alarm")}if(Server.Events.isMessage(rowValue)||Server.Events.isAlarm(rowValue))switch(rowValue.severity){case Server.Events.Severity.Verbose:classes.push("verbose");break;case Server.Events.Severity.Info:classes.push("info");break;case Server.Events.Severity.Warning:classes.push("warning");break;case Server.Events.Severity.Error:classes.push("error");break;case Server.Events.Severity.Critical:classes.push("critical")}if(Server.Events.isAlarm(rowValue)){switch(rowValue.alarmState){case Server.Events.AlarmState.Raised:classes.push("raised");break;case Server.Events.AlarmState.Confirmed:classes.push("confirmed");break;case Server.Events.AlarmState.Cleared:classes.push("cleared");break;case Server.Events.AlarmState.ClearedAndConfirmed:classes.push("cleared-and-confirmed");break;case Server.Events.AlarmState.Invalid:classes.push("invalid")}rowValue.confirmationState===Server.Events.ConfirmationState.NotRequired||rowValue.confirmationState===Server.Events.ConfirmationState.NotSupported?classes.push("no-confirmation-needed"):rowValue.confirmationState===Server.Events.ConfirmationState.Reset&&classes.push("confirmation-reset")}return classes}Functions.registerFunctionEx("EventClassesProvider","TcHmi.Controls.Beckhoff.TcHmiEventGrid",EventClassesProvider);